module priority_encoder_8bit(
    input [7:0]         unasserted_data  ,
    output reg [2:0]    data_out ,
    output reg          valid    
);

always @(*) begin
    valid = |unasserted_data;
    if (unasserted_data[7])
        data_out = 3'd7;
    else if (unasserted_data[6])
        data_out = 3'd6;
    else if (unasserted_data[5])
        data_out = 3'd5;
    else if (unasserted_data[4])
        data_out = 3'd4;
    else if (unasserted_data[3])
        data_out = 3'd3;
    else if (unasserted_data[2])
        data_out = 3'd2;
    else if (unasserted_data[1])
        data_out = 3'd1;
    else if (unasserted_data[0])
        data_out = 3'd0;
    else
        data_out = 3'd0;
end

endmodule
